"use client";

import { useEffect, useMemo, useState } from "react";
import type {
  ChatLanguage,
  ChatMessage,
  ConversationSummary
} from "@/lib/types";
import ChatSidebar from "./ChatSidebar";
import ChatWindow from "./ChatWindow";

const emptyMessages: ChatMessage[] = [];

const fetchJson = async <T,>(input: RequestInfo, init?: RequestInit) => {
  const response = await fetch(input, init);
  if (!response.ok) {
    throw new Error("Request failed");
  }
  return (await response.json()) as T;
};

export default function ChatApp({ className }: { className?: string }) {
  const [conversations, setConversations] = useState<ConversationSummary[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>(emptyMessages);
  const [language, setLanguage] = useState<ChatLanguage>("en");
  const [input, setInput] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const activeConversation = useMemo(
    () => conversations.find((conversation) => conversation.id === activeId),
    [conversations, activeId]
  );

  const loadConversations = async () => {
    const data = await fetchJson<ConversationSummary[]>("/api/conversations");
    setConversations(data);
    if (data.length && !activeId) {
      setActiveId(data[0].id);
      setLanguage(data[0].language);
    }
  };

  const loadMessages = async (conversationId: string) => {
    const data = await fetchJson<ChatMessage[]>(
      `/api/messages?conversationId=${conversationId}`
    );
    setMessages(data);
  };

  useEffect(() => {
    loadConversations().catch(() => setError("Unable to load conversations."));
  }, []);

  useEffect(() => {
    if (!activeId) {
      setMessages(emptyMessages);
      return;
    }
    loadMessages(activeId).catch(() => setError("Unable to load messages."));
  }, [activeId]);

  useEffect(() => {
    if (activeConversation) {
      setLanguage(activeConversation.language);
    }
  }, [activeConversation]);

  const handleNewChat = () => {
    setActiveId(null);
    setMessages(emptyMessages);
    setLanguage("en");
    setInput("");
  };

  const handleRename = async (conversationId: string) => {
    const title = window.prompt("Rename conversation", "");
    if (!title) return;
    const updated = await fetchJson<ConversationSummary>(
      `/api/conversations/${conversationId}`,
      {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title })
      }
    );
    setConversations((prev) =>
      prev.map((item) => (item.id === conversationId ? updated : item))
    );
  };

  const handleDelete = async (conversationId: string) => {
    const confirmed = window.confirm("Delete this conversation?");
    if (!confirmed) return;
    await fetchJson(`/api/conversations/${conversationId}`, {
      method: "DELETE"
    });
    setConversations((prev) =>
      prev.filter((item) => item.id !== conversationId)
    );
    if (activeId === conversationId) {
      handleNewChat();
    }
  };

  const handleLanguageChange = async (nextLanguage: ChatLanguage) => {
    setLanguage(nextLanguage);
    if (!activeId) return;
    const updated = await fetchJson<ConversationSummary>(
      `/api/conversations/${activeId}`,
      {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ language: nextLanguage })
      }
    );
    setConversations((prev) =>
      prev.map((item) => (item.id === updated.id ? updated : item))
    );
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;
    setError(null);
    const userMessage: ChatMessage = {
      id: `local-${Date.now()}`,
      role: "user",
      content: input.trim(),
      createdAt: new Date().toISOString()
    };
    const streamingMessage: ChatMessage = {
      id: "streaming",
      role: "assistant",
      content: "",
      createdAt: new Date().toISOString()
    };
    setMessages((prev) => [...prev, userMessage, streamingMessage]);
    setInput("");
    setIsStreaming(true);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          conversationId: activeId ?? undefined,
          message: userMessage.content,
          language
        })
      });

      if (!response.ok || !response.body) {
        throw new Error("Streaming failed");
      }

      const newConversationId =
        response.headers.get("x-conversation-id") ?? activeId;
      if (!activeId && newConversationId) {
        setActiveId(newConversationId);
        await loadConversations();
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let assistantText = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        assistantText += decoder.decode(value, { stream: true });
        setMessages((prev) =>
          prev.map((msg) =>
            msg.id === "streaming" ? { ...msg, content: assistantText } : msg
          )
        );
      }

      setMessages((prev) =>
        prev.map((msg) =>
          msg.id === "streaming"
            ? { ...msg, content: assistantText, id: `assistant-${Date.now()}` }
            : msg
        )
      );
    } catch {
      setError("Failed to send message.");
      setMessages((prev) => prev.filter((msg) => msg.id !== "streaming"));
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className={`flex h-full ${className ?? ""}`}>
      <ChatSidebar
        conversations={conversations}
        activeId={activeId}
        onSelect={setActiveId}
        onNew={handleNewChat}
        onRename={handleRename}
        onDelete={handleDelete}
      />
      <ChatWindow
        messages={messages}
        input={input}
        onInputChange={setInput}
        onSend={handleSend}
        isStreaming={isStreaming}
        language={language}
        onLanguageChange={handleLanguageChange}
        error={error}
      />
    </div>
  );
}
