import type { ConversationSummary } from "@/lib/types";

type Props = {
  conversations: ConversationSummary[];
  activeId: string | null;
  onSelect: (id: string) => void;
  onNew: () => void;
  onRename: (id: string) => void;
  onDelete: (id: string) => void;
};

export default function ChatSidebar({
  conversations,
  activeId,
  onSelect,
  onNew,
  onRename,
  onDelete
}: Props) {
  return (
    <aside className="hidden h-full w-64 flex-col border-r border-slate-200 bg-white lg:flex">
      <div className="flex items-center justify-between border-b border-slate-200 px-4 py-3">
        <span className="text-sm font-semibold text-slate-700">
          Conversations
        </span>
        <button
          className="rounded-md bg-slate-900 px-2 py-1 text-xs font-semibold text-white"
          onClick={onNew}
        >
          New
        </button>
      </div>
      <div className="flex-1 overflow-y-auto px-3 py-2">
        {conversations.length === 0 && (
          <p className="text-xs text-slate-500">No conversations yet.</p>
        )}
        <ul className="space-y-1">
          {conversations.map((conversation) => (
            <li key={conversation.id}>
              <button
                className={`flex w-full flex-col rounded-md px-3 py-2 text-left text-sm ${
                  activeId === conversation.id
                    ? "bg-slate-900 text-white"
                    : "text-slate-700 hover:bg-slate-100"
                }`}
                onClick={() => onSelect(conversation.id)}
              >
                <span className="font-medium">{conversation.title}</span>
                <span className="text-xs opacity-70">
                  {conversation.language.toUpperCase()}
                </span>
              </button>
              <div className="mt-1 flex gap-2 px-2 text-xs text-slate-500">
                <button
                  className="hover:text-slate-800"
                  onClick={() => onRename(conversation.id)}
                >
                  Rename
                </button>
                <button
                  className="hover:text-rose-600"
                  onClick={() => onDelete(conversation.id)}
                >
                  Delete
                </button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </aside>
  );
}
